// One folder per submission
// --------------------------------------------------
const issueBatchId = generateUUID();
const uploadedUrls = [];

// --------------------------------------------------
// Upload loop (SEQUENTIAL on purpose — iPad-safe)
// --------------------------------------------------
for (const item of rawInputs) {
  if (!item) continue;

  // 1️⃣ Convert blob URL → base64 data URL
  const dataUrl = await utils.getDataByObjectURL(item);

  if (!dataUrl || !dataUrl.startsWith("data:")) {
    throw new Error("Failed to read image data");
  }

  const [meta, base64] = dataUrl.split(",");
  const contentType =
    meta.match(/data:(.*);base64/)?.[1] || "image/jpeg";

  // 2️⃣ Decode base64 → binary
  const binary = Uint8Array.from(
    atob(base64),
    c => c.charCodeAt(0)
  );

  // 3️⃣ Generate UNIQUE filename
  const fileId = generateUUID();
  const extension = contentType.includes("png") ? "png" : "jpg";

  const filePath =
    `issues/${issueBatchId}/${fileId}.${extension}`;

  // 4️⃣ Get signed upload URL (NO transformer)
  const signed = await uploadImage_supabae.trigger({
    additionalScope: {
      filePath,
      contentType
    }
  });

  if (!signed?.uploadUrl || !signed?.publicUrl) {
    throw new Error("Failed to obtain signed upload URL");
  }

  // 5️⃣ Upload binary
  const res = await fetch(signed.uploadUrl, {
    method: "PUT",
    headers: {
      "Content-Type": contentType
    },
    body: binary
  });

  if (!res.ok) {
    throw new Error(await res.text());
  }

  uploadedUrls.push(signed.publicUrl);
}

